mapper.select:
select class_info.class_id, class_info.class_code, class_info.class_name, class_info.grade, class_info.entry_year, class_info.school_year, class_info.status, class_info.create_time, class_info.remark, class_teacher.user_id, sys_user.nick_name from class_info left join class_teacher on class_info.class_id = class_teacher.class_id and class_teacher.is_leader = '1' and class_teacher.status = '0' left join sys_user on class_teacher.user_id = sys_user.user_id
and class_name like concat('%', #{className}, '%') and grade = #{grade} and class_teacher.status = #{status}
order by entry_year desc, grade asc

mapper.update:
update class_info
class_code = #{classCode}, class_name = #{className}, grade = #{grade}, entry_year = #{entryYear}, school_year = #{schoolYear}, status = #{status}, remark = #{remark}
where class_id = #{classId}
